import DynamicHomepage from "@/components/home/DynamicHomepage";
import { fetchHomepageComponents, getActiveComponents } from "@/services/contentService";

export const dynamic = 'force-dynamic';

export default async function Home() {
  // Fetch homepage components from admin API
  let components;
  let activeComponents;
  
  try {
    components = await fetchHomepageComponents();
    activeComponents = getActiveComponents(components);
    console.log('[HomePage] Successfully fetched components from admin:', Object.keys(activeComponents));
    console.log('[HomePage] All components:', Object.keys(components));
    console.log('[HomePage] Featured Products component:', components.featuredProducts);
    console.log('[HomePage] Featured Products isActive:', components.featuredProducts?.isActive);
    console.log('[HomePage] Active featured products:', activeComponents.featuredProducts);
  } catch (error) {
    console.error('[HomePage] Failed to fetch components:', error);
    // Use default behavior if fetch fails
    activeComponents = {};
  }

  return <DynamicHomepage initialComponents={activeComponents} />;
}
